#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 55;
const LL Mod = 10000;
struct Mat{LL n,m,a[N][N];}H[12],B,Ans;
LL n,m,St,Ed,K,Fish,sry[N][12],Step,Sum;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
Mat operator * (const Mat &X , const Mat &Y){
    Mat Z;Z.n=X.n,Z.m=Y.m;
    for(int i=1;i<=Z.n;i++)
        for(int j=1;j<=Z.m;j++)Z.a[i][j]=0;
    for(int i=1;i<=Z.n;i++)for(int j=1;j<=Z.m;j++)
        for(int k=1;k<=X.m;k++)Z.a[i][j]=(Z.a[i][j]+X.a[i][k]*Y.a[k][j])%Mod;
    return Z;
}
Mat QP(Mat A,Mat X,LL Y){while(Y){if(Y&1)A=A*X;X=X*X,Y>>=1;}return A;}
int main(){
    n=read(),m=read();
    St=read()+1,Ed=read()+1,K=read();
    for(int i=0;i<12;i++)H[i].n=n,H[i].m=n;
    for(int i=1;i<=m;i++){
        int x=read()+1,y=read()+1;
        for(int j=0;j<12;j++)H[j].a[x][y]=1,H[j].a[y][x]=1;
    }
    Fish=read();
    for(int i=1;i<=Fish;i++){
        int c=read();
        for(int j=0;j<c;j++)sry[i][j]=read()+1;
        for(int j=c;j<12;j++)sry[i][j]=sry[i][j%c];
        for(int j=0;j<12;j++){
            int x=sry[i][j];
            for(int y=1;y<=n;y++)H[j].a[x][y]=0;
        }
    }
    B.n=n,B.m=n;
    for(int i=1;i<=n;i++)B.a[i][i]=1;
    for(int i=0;i<12;i++)B=B*H[i];
    Ans.n=1,Ans.m=n,Ans.a[1][St]=1;
    Ans=QP(Ans,B,K/12),Step=K%12;
    for(int i=0;i<Step;i++)Ans=Ans*H[i];
    cout<<Ans.a[1][Ed]<<"\n";
    return 0;
}
